enum Category {
	// Dummy category indicates an actual category is being fetched
	Pending = 'YT_DUMMY_CATEGORY_PENDING',
	// Fallback value in case when we cannot fetch a category.
	Unknown = 'YT_DUMMY_CATEGORY_UNKNOWN',
	Music = 'Music',
	Entertainment = 'Entertainment',
}

/**
 * Array of categories allowed to be scrobbled.
 */
const allowedCategories: string[] = [];

/**
 * Wether we should only scrobble music recognised by YouTube Music
 */
let scrobbleMusicRecognisedOnly = false;

/**
 * Wether the Youtube Music track info getter is enabled
 */
let ytMusicEnabled = false;
/**
 * Wether the Youtube Watch track info getter is enabled
 */
let ytWatchEnabled = false;
/**
 * Wether the Youtube Account track info getter is enabled
 */
let ytChannelEnabled = false;

/**
 * Wether we should only use attributed songs if Auto-generated
 */
let useAttributedOnlyForAutoGenerated = false;

type CacheValue<T> =
	| { done: false }
	| ({ done: true } & (T | { error: string }))
	| undefined;

type YoutubeChannelInfo = {
	musicArtistName: string | null;
};
/**
 * caches results of https://youtube.com/channel/${channelId} requests
 */
const youtubeChannelCache: {
	[channelId: string]: CacheValue<YoutubeChannelInfo>;
} = {};

type YoutubeWatchInfo = {
	category: string;
	title: string;
	channel: string;

	channelId: string;
	attributedTrackInfo?: {
		trackArt?: string;
		track?: string;
		artist?: string;
		album?: string;
	};

	chapters: {
		title: string;
		time: number;
	}[];
};
/**
 * caches results of https://youtube.com/watch?v=${videoId} requests
 */
const youtubeWatchCache: {
	[videoId: string]: CacheValue<YoutubeWatchInfo>;
} = {};

type YoutubeMusicInfo = {
	recognisedByYtMusic: boolean;
	currentTrackInfo: { artist?: string; track?: string };
};
/**
 * caches results of https://music.youtube.com/youtubei/v1/player requests
 */
const youtubeMusicCache: {
	[videoId: string]: CacheValue<YoutubeMusicInfo>;
} = {};

